import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'accent';
}

export const WesternButton: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', ...props }) => {
  const base = "px-8 py-3 uppercase font-bold transition-all transform hover:-translate-y-1 active:translate-y-0 anime-font text-lg tracking-wider skew-x-[-12deg] ";
  const variants = {
    primary: "vibrant-gradient text-white border-b-4 border-indigo-900 shadow-[4px_4px_0px_#312e81] hover:shadow-none hover:translate-x-1",
    secondary: "bg-slate-800 text-cyan-400 border-2 border-cyan-500/50 hover:bg-slate-700",
    accent: "bg-amber-400 text-slate-900 border-b-4 border-amber-700 hover:bg-amber-300 shadow-[4px_4px_0px_#92400e]"
  };

  return (
    <button className={`${base} ${variants[variant]} ${className}`} {...props}>
      <span className="inline-block skew-x-[12deg]">{children}</span>
    </button>
  );
};

export const BorderedCard: React.FC<{ children: React.ReactNode, className?: string, title?: string }> = ({ children, className = '', title }) => {
  return (
    <div className={`glass-bg rounded-tr-3xl rounded-bl-3xl border-l-4 border-t-2 border-indigo-500/50 shadow-2xl relative overflow-hidden ${className}`}>
      {/* Decorative anime elements */}
      <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-500/10 rotate-45 translate-x-12 -translate-y-12"></div>

      {title && (
        <div className="bg-indigo-600/20 backdrop-blur-md text-cyan-300 py-3 px-6 anime-font text-xl border-b border-indigo-500/30 flex justify-between items-center">
          <span>{title}</span>
          <div className="flex space-x-1">
            <div className="w-2 h-2 bg-indigo-400 rounded-full animate-pulse"></div>
            <div className="w-2 h-2 bg-rose-400 rounded-full animate-pulse delay-75"></div>
          </div>
        </div>
      )}
      <div className="p-6 relative z-10">
        {children}
      </div>
    </div>
  );
};

export const StatsBar: React.FC<{ label: string, value: number, max?: number, color?: string }> = ({ label, value, max = 100, color = "from-cyan-500 to-blue-600" }) => {
  const percentage = Math.min((value / max) * 100, 100);
  return (
    <div className="mb-4">
      <div className="flex justify-between text-xs mb-1.5 uppercase font-bold text-slate-400 system-font">
        <span className="text-cyan-400">{label}</span>
        <span className="text-white">{value} <span className="text-slate-500">/ {max}</span></span>
      </div>
      <div className="h-2.5 bg-slate-950/60 rounded-full overflow-hidden border border-white/5 p-[1px]">
        <div 
          className={`h-full bg-gradient-to-r ${color} transition-all duration-700 ease-out rounded-full shadow-[0_0_10px_rgba(6,182,212,0.5)]`} 
          style={{ width: `${percentage}%` }}
        ></div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuestNarrative = async (questTitle: string, characterName: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Narrate a short, high-octane summary of ${characterName} completing the mission "${questTitle}". Use a vibrant Shonen anime style with flashy moves, dramatic declarations, and frontier spirit. Max 3 sentences.`,
      config: {
        temperature: 0.9,
      }
    });
    return response.text || "Mission complete! The legend grows.";
  } catch (error) {
    console.error("Narrative generation failed", error);
    return "The dust settled as another legend was written in the frontier.";
  }
};

export const generateDuelNarrative = async (player: string, opponent: string, result: 'Win' | 'Loss') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Describe a high-stakes quick-draw duel between ${player} and ${opponent} in the style of an anime climax. ${player} ${result === 'Win' ? 'delivers a decisive blow' : 'is momentarily outmatched'}. Max 2 sentences. Flashy and intense.`,
    });
    return response.text || `A flash of steel! ${result === 'Win' ? player : opponent} stands victorious.`;
  } catch (error) {
    return `A flash of steel! ${result === 'Win' ? player : opponent} stands victorious.`;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Character, Item, Scene, Slot, Quest } from './types';
import { INITIAL_ITEMS, SHOP_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar } from './components/UI';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
import { Beer, ShieldCheck, Hammer, Sword, User, Package, Coins, Trophy, Zap, Crosshair, Heart, Flame, Wind } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  const [character, setCharacter] = useState<Character>({
    name: 'Sora the Gunner',
    level: 1,
    exp: 0,
    gold: 500,
    baseStats: { aim: 15, reflexes: 12, grit: 10, charisma: 8, stamina: 12 },
    equipment: { Hat: null, Revolver: null, Rifle: null, Poncho: null, Boots: null, Badge: null, Belt: null },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [lastNarrative, setLastNarrative] = useState<string>('');
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);

  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    (Object.values(character.equipment) as (Item | null)[]).forEach(item => {
      if (item?.stats) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          if (typeof val === 'number') (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  useEffect(() => {
    if (!activeQuest) return;
    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.duration - Math.floor((Date.now() - prev.startTime) / 1000));
        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [activeQuest]);

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    const story = await generateQuestNarrative(quest.title, character.name);
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    setCharacter(prev => ({ ...prev, gold: prev.gold + quest.reward.gold, exp: prev.exp + quest.reward.exp, level: Math.floor((prev.exp + quest.reward.exp) / 1000) + 1 }));
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;
    const slot = item.slot;
    const currentEquipped = character.equipment[slot];
    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;
      return { ...prev, equipment: { ...prev.equipment, [slot]: item }, inventory: newInventory };
    });
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;
    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) return prev;
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;
      return { ...prev, equipment: { ...prev.equipment, [slot]: null }, inventory: newInventory };
    });
  };

  const buyItem = (item: Item) => {
    if (character.gold < item.price) return alert("Insufficient Gold, Rookie!");
    const emptyIdx = character.inventory.findIndex(i => i === null);
    if (emptyIdx === -1) return alert("Your bags are full!");
    setCharacter(prev => ({ ...prev, gold: prev.gold - item.price, inventory: prev.inventory.map((slot, i) => i === emptyIdx ? { ...item, id: `${item.id}-${Date.now()}` } : slot) }));
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) return;
    setActiveQuest({ quest, timeRemaining: quest.duration, startTime: Date.now() });
    setLastNarrative(`Engaging objective: ${quest.title}...`);
  };

  const runDuel = async () => {
    const win = totalStats.aim + totalStats.reflexes > 35;
    setIsLoadingNarrative(true);
    const story = await generateDuelNarrative(character.name, "Dark Phantom", win ? 'Win' : 'Loss');
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    if (win) setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#0f172a] text-slate-100">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-72 glass-bg border-r border-indigo-500/30 flex flex-col p-6 z-10 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 vibrant-gradient"></div>
        <div className="mb-10 text-center">
          <h1 className="anime-font text-4xl text-white tracking-tighter drop-shadow-[0_0_10px_rgba(99,102,241,0.8)]">
            DUST <span className="text-rose-500">&</span> GLORY
          </h1>
          <div className="text-[10px] system-font uppercase tracking-[0.3em] text-cyan-400 mt-1">Advanced Frontier System v3.1</div>
        </div>

        <div className="space-y-3">
          {[
            { id: 'Character', icon: User, label: 'Hero Sheet' },
            { id: 'Saloon', icon: Beer, label: 'The Hub' },
            { id: 'Sheriff', icon: ShieldCheck, label: 'Bounty Board' },
            { id: 'Gunsmith', icon: Hammer, label: 'Tech Forge' },
            { id: 'HighNoon', icon: Sword, label: 'Arena' }
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentScene(item.id as Scene)}
              className={`w-full flex items-center space-x-4 p-4 anime-font text-xl transition-all rounded-lg group ${
                currentScene === item.id 
                ? 'bg-indigo-600/30 text-white shadow-[0_0_15px_rgba(99,102,241,0.3)] border border-indigo-400/50 translate-x-2' 
                : 'text-slate-400 hover:text-cyan-300 hover:bg-slate-800/50'
              }`}
            >
              <item.icon size={22} className={currentScene === item.id ? 'text-cyan-400' : 'group-hover:text-cyan-400'} />
              <span>{item.label}</span>
            </button>
          ))}
        </div>

        <div className="mt-auto pt-8 border-t border-white/5">
          <div className="grid grid-cols-2 gap-2 mb-4">
             <div className="bg-slate-950/50 p-2 rounded border border-white/5 flex items-center space-x-2">
                <Coins size={16} className="text-yellow-400" />
                <span className="system-font font-bold">{character.gold}</span>
             </div>
             <div className="bg-slate-950/50 p-2 rounded border border-white/5 flex items-center space-x-2">
                <Trophy size={16} className="text-cyan-400" />
                <span className="system-font font-bold">LV.{character.level}</span>
             </div>
          </div>
          <StatsBar label="EXP PROGRESS" value={character.exp % 1000} max={1000} color="from-indigo-500 to-rose-500" />
        </div>
      </nav>

      {/* Main Game Area */}
      <main className="flex-1 relative overflow-y-auto p-4 md:p-10">

        {/* Narrative Feedback Overlay */}
        {(lastNarrative || isLoadingNarrative) && (
          <div className="mb-8 animate-in slide-in-from-top-4 duration-500">
            <BorderedCard className="bg-gradient-to-br from-indigo-900/40 to-slate-900/60 border-indigo-400/30">
              <div className="flex items-center space-x-3 mb-3">
                <Zap className="text-yellow-400 animate-pulse" size={20} />
                <h3 className="anime-font text-2xl text-cyan-300">Frontier Intel</h3>
              </div>
              <p className="system-font text-lg text-slate-100 leading-relaxed italic">
                {isLoadingNarrative ? "> Syncing with neural network..." : `> "${lastNarrative}"`}
              </p>
              {activeQuest && (
                <div className="mt-6">
                  <div className="flex justify-between text-[10px] system-font text-cyan-500 mb-1">
                    <span>DEPLOYED: {activeQuest.quest.title}</span>
                    <span>{activeQuest.timeRemaining}S TO COMPLETION</span>
                  </div>
                  <div className="h-1.5 bg-slate-950 rounded-full overflow-hidden">
                    <div 
                      className="h-full vibrant-gradient transition-all shadow-[0_0_8px_#6366f1]" 
                      style={{ width: `${(activeQuest.timeRemaining / activeQuest.quest.duration) * 100}%` }}
                    ></div>
                  </div>
                </div>
              )}
            </BorderedCard>
          </div>
        )}

        <div className="max-w-6xl mx-auto h-full">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {/* Paper Doll View */}
              <div className="flex flex-col">
                <h2 className="anime-font text-5xl mb-8 text-white flex items-center">
                  <User className="mr-4 text-indigo-400" /> SYSTEM PROFILE
                </h2>
                <div className="relative aspect-[3/4] max-w-sm mx-auto w-full bg-slate-950/40 rounded-3xl border-2 border-indigo-500/20 p-8 flex flex-col items-center overflow-hidden">
                  <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(99,102,241,0.1)_0%,transparent_70%)] animate-pulse"></div>

                  {/* Equipment Grid Layout */}
                  <div className="relative z-10 w-full h-full grid grid-cols-3 grid-rows-5 gap-4">
                    <div className="col-start-2 row-start-1 flex justify-center">
                      <EquipmentSlot slot="Hat" item={character.equipment.Hat} onUnequip={() => handleUnequip('Hat')} />
                    </div>
                    <div className="col-start-1 row-start-2 flex justify-center">
                      <EquipmentSlot slot="Revolver" item={character.equipment.Revolver} onUnequip={() => handleUnequip('Revolver')} />
                    </div>
                    <div className="col-start-2 row-start-2 flex flex-col items-center space-y-2">
                       <EquipmentSlot slot="Poncho" item={character.equipment.Poncho} onUnequip={() => handleUnequip('Poncho')} />
                    </div>
                    <div className="col-start-3 row-start-2 flex justify-center">
                      <EquipmentSlot slot="Rifle" item={character.equipment.Rifle} onUnequip={() => handleUnequip('Rifle')} />
                    </div>
                    <div className="col-start-2 row-start-3 flex justify-center">
                       <EquipmentSlot slot="Badge" item={character.equipment.Badge} onUnequip={() => handleUnequip('Badge')} />
                    </div>
                    <div className="col-start-1 row-start-5 flex justify-center">
                      <EquipmentSlot slot="Belt" item={character.equipment.Belt} onUnequip={() => handleUnequip('Belt')} />
                    </div>
                    <div className="col-start-3 row-start-5 flex justify-center">
                      <EquipmentSlot slot="Boots" item={character.equipment.Boots} onUnequip={() => handleUnequip('Boots')} />
                    </div>
                  </div>
                </div>

                <BorderedCard className="mt-8" title="VITAL PARAMETERS">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8">
                    <StatsBar label="Precision (Aim)" value={totalStats.aim} max={150} color="from-rose-500 to-orange-500" />
                    <StatsBar label="Sync Speed (Reflexes)" value={totalStats.reflexes} max={150} color="from-cyan-400 to-indigo-500" />
                    <StatsBar label="Fortitude (Grit)" value={totalStats.grit} max={150} color="from-green-400 to-emerald-600" />
                    <StatsBar label="Influence (Charisma)" value={totalStats.charisma} max={150} color="from-purple-400 to-pink-500" />
                  </div>
