              </div>

              {/* Inventory View */}
              <div className="flex flex-col">
                 <h2 className="anime-font text-5xl mb-8 text-white flex items-center">
                   <Package className="mr-4 text-rose-500" /> CARGO STORAGE
                 </h2>
                 <BorderedCard className="flex-1" title="DIGITAL INVENTORY">
                    <div className="grid grid-cols-4 md:grid-cols-5 gap-3">
                      {character.inventory.map((item, idx) => (
                        <div 
                          key={idx}
                          onClick={() => item && setSelectedInventoryIdx(selectedInventoryIdx === idx ? null : idx)}
                          className={`aspect-square rounded-xl border-2 relative cursor-pointer flex flex-col items-center justify-center transition-all overflow-hidden ${
                            selectedInventoryIdx === idx 
                            ? 'border-cyan-400 bg-indigo-600/40 shadow-[0_0_15px_rgba(34,211,238,0.4)] scale-105 z-10' 
                            : 'border-white/5 bg-slate-900/80 hover:border-indigo-500/50 hover:bg-slate-800'
                          }`}
                        >
                          {item ? (
                            <>
                              <div className={`absolute top-0 left-0 w-full h-1 bg-gradient-to-r ${rarityGradient(item.rarity)}`}></div>
                              <span className={`text-[8px] font-bold mt-2 uppercase ${rarityText(item.rarity)}`}>{item.slot}</span>
                              <div className="p-1 text-center">
                                <span className="text-[10px] leading-tight text-white font-bold">{item.name}</span>
                              </div>
                            </>
                          ) : (
                            <div className="opacity-10"><Package size={20} /></div>
                          )}
                        </div>
                      ))}
                    </div>

                    {selectedInventoryIdx !== null && character.inventory[selectedInventoryIdx] && (
                      <div className="mt-8 bg-slate-950/80 p-6 rounded-2xl border border-indigo-500/30 animate-in zoom-in-95 duration-200">
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <h4 className="anime-font text-2xl text-white">{character.inventory[selectedInventoryIdx]!.name}</h4>
                            <span className={`text-[10px] font-bold uppercase tracking-widest ${rarityText(character.inventory[selectedInventoryIdx]!.rarity)}`}>
                              LEVEL: {character.inventory[selectedInventoryIdx]!.rarity} GEAR
                            </span>
                          </div>
                          <div className={`px-3 py-1 rounded text-[10px] font-bold bg-slate-900 border ${rarityBorder(character.inventory[selectedInventoryIdx]!.rarity)}`}>
                             ID: {character.inventory[selectedInventoryIdx]!.id.slice(0,6)}
