                        </div>
                        <p className="system-font text-sm text-slate-400 mb-6 leading-relaxed">"{character.inventory[selectedInventoryIdx]!.description}"</p>
                        <div className="flex flex-wrap gap-2 mb-8">
                          {Object.entries(character.inventory[selectedInventoryIdx]!.stats).map(([s, v]) => (
                            <div key={s} className="bg-indigo-500/10 border border-indigo-500/20 px-3 py-1.5 rounded-lg flex items-center space-x-2">
