               <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full">
                  <BorderedCard title="AVAILABLE MISSIONS" className="bg-indigo-950/20">
                    <p className="system-font mb-8 text-slate-300 text-sm border-l-4 border-rose-500 pl-4 bg-rose-500/5 py-3 rounded-r-lg">
                      Neural link established. The board is flickering with new frontier requests. Pick your challenge, Gunner.
                    </p>
                    <div className="space-y-4">
                      {QUESTS.map(q => (
                        <div key={q.id} className="p-5 rounded-xl border border-white/5 bg-slate-900/50 flex justify-between items-center group hover:bg-slate-800 transition-all hover:border-indigo-500/40">
