                  <div className="flex flex-col space-y-10">
                    <div className="relative group overflow-hidden rounded-3xl border-2 border-indigo-500/20 shadow-2xl">
                       <img src="https://images.unsplash.com/photo-1614728263952-84ea206f99b6?auto=format&fit=crop&q=80&w=800" className="w-full h-64 object-cover opacity-60 group-hover:scale-110 transition-transform duration-1000" alt="Cyber Saloon" />
                       <div className="absolute inset-0 bg-gradient-to-t from-[#0f172a] via-transparent to-transparent"></div>
                       <div className="absolute bottom-6 left-6">
                         <div className="anime-font text-3xl text-white">CITY OF LIGHTS</div>
                         <div className="text-[10px] system-font text-cyan-400 uppercase">Sector 7 Frontier Hub</div>
                       </div>
                    </div>
                    <BorderedCard title="COMMANDER'S LOG">
                      <p className="system-font text-slate-400 mb-6 italic text-sm">"In this world, the fastest draw isn't enough. You need the heart of a lion and the mind of a machine."</p>
                      <WesternButton variant="accent" className="w-full" onClick={() => alert("The commander nods in respect.")}>PURCHASE INTEL (50C)</WesternButton>
                    </BorderedCard>
                  </div>
               </div>
            </div>
          )}

          {currentScene === 'HighNoon' && (
            <div className="flex flex-col items-center justify-center h-full min-h-[500px] relative overflow-hidden rounded-3xl bg-slate-950/40 border-2 border-white/5">
              <div className="absolute inset-0 bg-[linear-gradient(rgba(99,102,241,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(99,102,241,0.05)_1px,transparent_1px)] bg-[size:40px_40px]"></div>

              <h2 className="anime-font text-8xl mb-2 text-white animate-bounce tracking-tighter">CLIMAX!</h2>
              <p className="anime-font text-2xl text-rose-500 mb-16 tracking-widest uppercase">Showdown at the Edge of Fate</p>

              <div className="flex flex-col md:flex-row items-center space-y-12 md:space-y-0 md:space-x-32 relative z-10">
                {/* Player side */}
                <div className="flex flex-col items-center group">
                   <div className="w-44 h-44 rounded-full border-4 border-cyan-400 bg-slate-900 flex items-center justify-center overflow-hidden shadow-[0_0_30px_rgba(34,211,238,0.3)] group-hover:scale-110 transition-transform">
                     <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=hero" className="w-full h-full object-cover" alt="Hero" />
