                <div className="anime-font text-7xl text-rose-600 animate-pulse drop-shadow-[0_0_20px_rgba(225,29,72,0.8)] z-10">VERSUS</div>

                {/* Opponent side */}
                <div className="flex flex-col items-center group">
                   <div className="w-44 h-44 rounded-full border-4 border-rose-600 bg-slate-900 flex items-center justify-center overflow-hidden shadow-[0_0_30px_rgba(225,29,72,0.3)] group-hover:scale-110 transition-transform">
                     <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=shadow" className="w-full h-full object-cover brightness-50 contrast-125" alt="Boss" />
                   </div>
                   <h3 className="anime-font text-3xl mt-6 text-white">DARK PHANTOM</h3>
                   <div className="mt-2 px-4 py-1 bg-rose-500/10 rounded-full text-[10px] system-font text-rose-500 font-bold uppercase tracking-widest">AIM: 25</div>
                </div>
              </div>

              <div className="mt-20 relative">
                 <div className="absolute -inset-8 vibrant-gradient blur-3xl opacity-20 animate-pulse"></div>
                 <WesternButton 
                   variant="primary" 
                   className="text-4xl px-20 py-6 rounded-none shadow-[10px_10px_0px_#1e1b4b] relative z-10"
                   onClick={runDuel}
                   disabled={isLoadingNarrative}
                 >
                   {isLoadingNarrative ? "SYNCING..." : "FULL DRAW!"}
                 </WesternButton>
              </div>
            </div>
          )}

          {/* Simple Fallbacks for Other Scenes to maintain code size */}
          {(currentScene === 'Sheriff' || currentScene === 'Gunsmith') && (
            <div className="flex flex-col items-center justify-center h-full text-center">
              <h2 className="anime-font text-6xl text-white mb-4 uppercase">{currentScene} DEPOT</h2>
              <p className="system-font text-cyan-400 text-lg mb-8 tracking-widest">COMMING SOON IN THE NEXT EXPANSION...</p>
              <BorderedCard title="SYSTEM MAINTENANCE" className="max-w-md">
                <p className="text-slate-400 text-sm italic">"We're currently calibrating the local forge and bounty network. Please check back after your next mission."</p>
              </BorderedCard>
              <WesternButton variant="secondary" className="mt-10" onClick={() => setCurrentScene('Character')}>Return to HQ</WesternButton>
            </div>
          )}
        </div>
      </main>

      {/* Mobile Footer */}
      <footer className="md:hidden sticky bottom-0 w-full glass-bg border-t border-indigo-500/30 p-4 flex justify-between items-center z-20">
         <div className="flex items-center space-x-3 text-white anime-font text-xl">
           <Coins size={20} className="text-yellow-400" />
           <span>{character.gold}C</span>
         </div>
         <WesternButton onClick={() => setCurrentScene('Character')} className="py-2 px-6 text-sm" variant="secondary">MENU</WesternButton>
      </footer>
    </div>
  );
};

