const rarityGradient = (r: string) => {
  switch (r) {
    case 'Common': return 'from-slate-500 to-slate-600';
    case 'Uncommon': return 'from-emerald-400 to-teal-500';
    case 'Rare': return 'from-cyan-400 to-blue-600';
    case 'Epic': return 'from-purple-500 to-indigo-600';
    case 'Legendary': return 'from-amber-400 to-rose-500';
    default: return 'from-white to-slate-300';
  }
};

const rarityText = (r: string) => {
  switch (r) {
    case 'Common': return 'text-slate-400';
    case 'Uncommon': return 'text-emerald-400';
    case 'Rare': return 'text-cyan-400';
    case 'Epic': return 'text-purple-400';
    case 'Legendary': return 'text-amber-400';
    default: return 'text-white';
  }
};

const rarityBorder = (r: string) => {
  switch (r) {
    case 'Common': return 'border-slate-700';
    case 'Uncommon': return 'border-emerald-500/30';
    case 'Rare': return 'border-cyan-500/30';
    case 'Epic': return 'border-purple-500/30';
    case 'Legendary': return 'border-amber-500/30';
    default: return 'border-white/10';
  }
};

export default App;

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'accent';
}

export const WesternButton: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', ...props }) => {
  const base = "px-8 py-3 uppercase font-bold transition-all transform hover:-translate-y-0.5 active:translate-y-0.5 western-font text-lg tracking-wider border-2 ";
  const variants = {
    primary: "bg-[#cb9651] text-[#250f0b] border-[#663219] shadow-[4px_4px_0px_#250f0b] hover:bg-[#e4c388] hover:shadow-[2px_2px_0px_#250f0b]",
    secondary: "bg-[#663219] text-[#e4c388] border-[#a06335] shadow-[4px_4px_0px_#250f0b] hover:bg-[#a06335]",
    accent: "bg-[#e4c388] text-[#250f0b] border-[#cb9651] shadow-[4px_4px_0px_#250f0b] hover:bg-white"
  };

  return (
    <button className={`${base} ${variants[variant]} ${className}`} {...props}>
      {children}
    </button>
  );
};

export const BorderedCard: React.FC<{ children: React.ReactNode, className?: string, title?: string }> = ({ children, className = '', title }) => {
  return (
    <div className={`wood-panel rounded-lg shadow-2xl relative overflow-hidden flex flex-col ${className}`}>
      {title && (
        <div className="bg-[#250f0b]/40 text-[#cb9651] py-3 px-6 western-font text-2xl border-b border-[#a06335]/30 flex justify-between items-center">
