          <div className="flex space-x-1">
             <div className="w-1.5 h-1.5 bg-[#cb9651] rotate-45"></div>
             <div className="w-1.5 h-1.5 bg-[#cb9651] rotate-45"></div>
          </div>
        </div>
      )}
      <div className="p-6 relative z-10 flex-1">
        {children}
      </div>
    </div>
  );
};

export const StatsBar: React.FC<{ label: string, value: number, max?: number, color?: string, tooltip?: string }> = ({ label, value, max = 100, color = "from-[#cb9651] to-[#a06335]", tooltip }) => {
  const percentage = Math.min((value / max) * 100, 100);
  return (
    <div className="mb-6 group">
      <div className="flex justify-between text-xs mb-1.5 uppercase font-bold text-[#e4c388]/80 typewriter-font items-center">
        <div className="tooltip">
          <span className="border-b border-dotted border-[#cb9651] cursor-help hover:text-[#cb9651]">{label}</span>
          {tooltip && <span className="tooltiptext">{tooltip}</span>}
        </div>
        <span className="text-white bg-[#250f0b] px-2 py-0.5 rounded border border-[#663219]">{value} <span className="text-[#a06335]">/ {max}</span></span>
      </div>
      <div className="h-3 bg-[#250f0b] rounded-sm overflow-hidden border border-[#663219] p-[1px] shadow-inner">
        <div 
          className={`h-full bg-gradient-to-r ${color} transition-all duration-1000 ease-in-out rounded-sm`} 
          style={{ width: `${percentage}%` }}
        ></div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Character, Item, Scene, Slot, Quest } from './types';
import { INITIAL_ITEMS, SHOP_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar } from './components/UI';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
import { Beer, ShieldCheck, Hammer, Sword, User, Package, Coins, Trophy, Zap, Crosshair, Heart, Flame, Wind, Info } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  const [character, setCharacter] = useState<Character>({
    name: 'Silas Vane',
    level: 1,
    exp: 0,
    gold: 500,
    baseStats: { aim: 15, reflexes: 12, grit: 10, charisma: 8, stamina: 12 },
    equipment: { Hat: null, Revolver: null, Rifle: null, Poncho: null, Boots: null, Badge: null, Belt: null },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [lastNarrative, setLastNarrative] = useState<string>('');
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);

  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    (Object.values(character.equipment) as (Item | null)[]).forEach(item => {
      if (item?.stats) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          if (typeof val === 'number') (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  useEffect(() => {
    if (!activeQuest) return;
    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.duration - Math.floor((Date.now() - prev.startTime) / 1000));
        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [activeQuest]);

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    const story = await generateQuestNarrative(quest.title, character.name);
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    setCharacter(prev => ({ ...prev, gold: prev.gold + quest.reward.gold, exp: prev.exp + quest.reward.exp, level: Math.floor((prev.exp + quest.reward.exp) / 1000) + 1 }));
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;
    const slot = item.slot;
    const currentEquipped = character.equipment[slot];
    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;
      return { ...prev, equipment: { ...prev.equipment, [slot]: item }, inventory: newInventory };
    });
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;
    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) return prev;
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;
      return { ...prev, equipment: { ...prev.equipment, [slot]: null }, inventory: newInventory };
    });
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) return;
    setActiveQuest({ quest, timeRemaining: quest.duration, startTime: Date.now() });
    setLastNarrative(`Embarking on mission: ${quest.title}...`);
  };

  const runDuel = async () => {
    const win = totalStats.aim + totalStats.reflexes > 35;
    setIsLoadingNarrative(true);
    const story = await generateDuelNarrative(character.name, "Blackjack Bart", win ? 'Win' : 'Loss');
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    if (win) setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#250f0b] text-[#e4c388]">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-72 bg-[#663219]/20 border-r border-[#a06335]/30 flex flex-col p-6 z-10 relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 left-0 w-full h-1 bg-[#cb9651]"></div>
        <div className="mb-10 text-center">
          <h1 className="western-font text-5xl text-[#cb9651] tracking-tighter drop-shadow-[2px_2px_0px_#250f0b]">
            DUST <span className="text-[#e4c388]">&</span> GLORY
          </h1>
          <div className="text-[10px] typewriter-font uppercase tracking-[0.2em] text-[#a06335] mt-2">Frontier Journal v1.0.4</div>
        </div>

        <div className="space-y-3">
          {[
            { id: 'Character', icon: User, label: 'Journal' },
            { id: 'Saloon', icon: Beer, label: 'The Saloon' },
            { id: 'Sheriff', icon: ShieldCheck, label: 'Sheriff Office' },
            { id: 'Gunsmith', icon: Hammer, label: 'Gunsmith' },
            { id: 'HighNoon', icon: Sword, label: 'High Noon' }
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentScene(item.id as Scene)}
              className={`w-full flex items-center space-x-4 p-4 western-font text-2xl transition-all rounded-sm border-l-4 ${
                currentScene === item.id 
                ? 'bg-[#cb9651] text-[#250f0b] border-[#250f0b] shadow-lg translate-x-2' 
                : 'text-[#a06335] border-transparent hover:text-[#cb9651] hover:bg-[#663219]/30'
              }`}
            >
              <item.icon size={22} className={currentScene === item.id ? 'text-[#250f0b]' : 'group-hover:text-[#cb9651]'} />
              <span>{item.label}</span>
            </button>
          ))}
        </div>

        <div className="mt-auto pt-8 border-t border-[#663219]">
          <div className="grid grid-cols-2 gap-2 mb-4">
             <div className="bg-[#250f0b]/60 p-2 rounded border border-[#a06335]/30 flex items-center space-x-2">
                <Coins size={16} className="text-[#cb9651]" />
                <span className="typewriter-font font-bold">{character.gold}</span>
             </div>
             <div className="bg-[#250f0b]/60 p-2 rounded border border-[#a06335]/30 flex items-center space-x-2">
                <Trophy size={16} className="text-[#cb9651]" />
                <span className="typewriter-font font-bold">LV.{character.level}</span>
             </div>
          </div>
          <StatsBar label="EXPERIENCE" value={character.exp % 1000} max={1000} color="from-[#663219] to-[#cb9651]" />
        </div>
      </nav>

      {/* Main Game Area */}
      <main className="flex-1 relative overflow-y-auto p-4 md:p-10">

        {/* Narrative Feedback Overlay */}
        {(lastNarrative || isLoadingNarrative) && (
          <div className="mb-8 animate-in slide-in-from-top-4 duration-500">
            <BorderedCard className="bg-[#e4c388]/5 border-[#cb9651]/30">
              <div className="flex items-center space-x-3 mb-3">
                <Zap className="text-[#cb9651]" size={20} />
                <h3 className="western-font text-2xl text-[#cb9651]">Tale from the Trail</h3>
              </div>
              <p className="typewriter-font text-lg text-[#e4c388] leading-relaxed italic bg-[#250f0b]/40 p-4 border border-[#663219]">
                {isLoadingNarrative ? "> Consultin' the stars..." : `"${lastNarrative}"`}
              </p>
              {activeQuest && (
                <div className="mt-6">
                  <div className="flex justify-between text-[10px] typewriter-font text-[#cb9651] mb-1">
                    <span>TASK: {activeQuest.quest.title}</span>
                    <span>{activeQuest.timeRemaining}S UNTIL SUNSET</span>
                  </div>
                  <div className="h-2 bg-[#250f0b] rounded-full overflow-hidden border border-[#663219]">
                    <div 
                      className="h-full bg-[#cb9651] transition-all" 
                      style={{ width: `${(activeQuest.timeRemaining / activeQuest.quest.duration) * 100}%` }}
                    ></div>
                  </div>
                </div>
              )}
            </BorderedCard>
          </div>
        )}

        <div className="max-w-6xl mx-auto h-full">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {/* Paper Doll View */}
              <div className="flex flex-col">
                <h2 className="western-font text-5xl mb-8 text-[#cb9651] flex items-center">
                  <User className="mr-4" /> THE GUNSLINGER
                </h2>
                <div className="relative aspect-[3/4] max-w-sm mx-auto w-full bg-[#250f0b]/60 rounded-lg border-4 border-[#663219] p-8 flex flex-col items-center overflow-hidden shadow-inner">
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')] opacity-10"></div>

                  {/* Equipment Grid Layout */}
                  <div className="relative z-10 w-full h-full grid grid-cols-3 grid-rows-5 gap-4">
                    <div className="col-start-2 row-start-1 flex justify-center">
                      <EquipmentSlot slot="Hat" item={character.equipment.Hat} onUnequip={() => handleUnequip('Hat')} />
                    </div>
                    <div className="col-start-1 row-start-2 flex justify-center">
                      <EquipmentSlot slot="Revolver" item={character.equipment.Revolver} onUnequip={() => handleUnequip('Revolver')} />
                    </div>
                    <div className="col-start-2 row-start-2 flex flex-col items-center">
                       <EquipmentSlot slot="Poncho" item={character.equipment.Poncho} onUnequip={() => handleUnequip('Poncho')} />
                    </div>
                    <div className="col-start-3 row-start-2 flex justify-center">
                      <EquipmentSlot slot="Rifle" item={character.equipment.Rifle} onUnequip={() => handleUnequip('Rifle')} />
                    </div>
                    <div className="col-start-2 row-start-3 flex justify-center">
                       <EquipmentSlot slot="Badge" item={character.equipment.Badge} onUnequip={() => handleUnequip('Badge')} />
                    </div>
                    <div className="col-start-1 row-start-5 flex justify-center">
                      <EquipmentSlot slot="Belt" item={character.equipment.Belt} onUnequip={() => handleUnequip('Belt')} />
                    </div>
                    <div className="col-start-3 row-start-5 flex justify-center">
                      <EquipmentSlot slot="Boots" item={character.equipment.Boots} onUnequip={() => handleUnequip('Boots')} />
                    </div>
                  </div>
                </div>

                <BorderedCard className="mt-8" title="VITAL PARAMETERS">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12">
                    <StatsBar 
                      label="Aim" 
                      value={totalStats.aim} 
                      max={150} 
                      color="from-[#663219] to-[#cb9651]" 
                      tooltip="Critical Accuracy. Higher Aim increases your chance of winning duels and dealing max damage."
                    />
                    <StatsBar 
                      label="Reflexes" 
                      value={totalStats.reflexes} 
                      max={150} 
                      color="from-[#663219] to-[#cb9651]" 
                      tooltip="Quick Draw. Reflexes determine your speed in combat and the ability to dodge incoming fire."
                    />
                    <StatsBar 
                      label="Grit" 
                      value={totalStats.grit} 
                      max={150} 
                      color="from-[#663219] to-[#cb9651]" 
                      tooltip="Toughness. Grit reduces incoming damage and allows you to survive longer expeditions."
                    />
                    <StatsBar 
                      label="Charisma" 
                      value={totalStats.charisma} 
                      max={150} 
                      color="from-[#663219] to-[#cb9651]" 
                      tooltip="Social Influence. High Charisma leads to better rewards from quest-givers and cheaper shop prices."
                    />
                    <StatsBar 
                      label="Stamina" 
                      value={totalStats.stamina} 
                      max={150} 
                      color="from-[#663219] to-[#cb9651]" 
                      tooltip="Endurance. Increases the maximum duration of missions you can safely undertake."
                    />
                  </div>
                  <div className="flex items-center space-x-2 text-[#a06335] text-[10px] typewriter-font mt-2 border-t border-[#a06335]/20 pt-4">
                    <Info size={12} />
                    <span>Hover over a parameter to learn its secret.</span>
                  </div>
                </BorderedCard>
              </div>

              {/* Inventory View */}
              <div className="flex flex-col">
                 <h2 className="western-font text-5xl mb-8 text-[#cb9651] flex items-center">
                   <Package className="mr-4" /> SADDLEBAGS
                 </h2>
                 <BorderedCard className="flex-1" title="POSSESSIONS">
                    <div className="grid grid-cols-4 md:grid-cols-5 gap-3">
                      {character.inventory.map((item, idx) => (
                        <div 
                          key={idx}
                          onClick={() => item && setSelectedInventoryIdx(selectedInventoryIdx === idx ? null : idx)}
                          className={`aspect-square rounded border-2 relative cursor-pointer flex flex-col items-center justify-center transition-all ${
