                            <h4 className="western-font text-3xl text-[#cb9651]">{character.inventory[selectedInventoryIdx]!.name}</h4>
                            <span className={`text-[10px] typewriter-font font-bold uppercase tracking-widest ${rarityTextColor(character.inventory[selectedInventoryIdx]!.rarity)}`}>
                              {character.inventory[selectedInventoryIdx]!.rarity} Artifact
                            </span>
                          </div>
                          <div className="bg-[#663219] px-3 py-1 rounded text-[10px] typewriter-font text-[#e4c388] border border-[#cb9651]/40">
                             VAL: {character.inventory[selectedInventoryIdx]!.price}C
                          </div>
                        </div>
                        <p className="typewriter-font text-sm text-[#e4c388]/70 mb-6 italic leading-relaxed">"{character.inventory[selectedInventoryIdx]!.description}"</p>
                        <div className="flex flex-wrap gap-2 mb-8">
                          {Object.entries(character.inventory[selectedInventoryIdx]!.stats).map(([s, v]) => (
                            <div key={s} className="bg-[#cb9651]/10 border border-[#cb9651]/20 px-3 py-1.5 rounded flex items-center space-x-2">
