                              <span className="text-xs font-bold text-[#e4c388] typewriter-font uppercase">{s} +{v}</span>
                            </div>
                          ))}
                        </div>
                        <WesternButton 
                          onClick={() => handleEquip(selectedInventoryIdx!)} 
                          className="w-full"
                          variant="primary"
