const rarityColor = (r: string) => {
  switch (r) {
    case 'Common': return 'from-[#663219] to-[#a06335]';
    case 'Uncommon': return 'from-[#a06335] to-[#cb9651]';
    case 'Rare': return 'from-[#cb9651] to-[#e4c388]';
    case 'Epic': return 'from-red-800 to-red-600';
    case 'Legendary': return 'from-yellow-600 to-yellow-300';
    default: return 'from-[#663219] to-[#a06335]';
  }
};

const rarityTextColor = (r: string) => {
  switch (r) {
    case 'Common': return 'text-[#a06335]';
    case 'Uncommon': return 'text-[#cb9651]';
    case 'Rare': return 'text-[#e4c388]';
    case 'Epic': return 'text-red-500';
    case 'Legendary': return 'text-yellow-400';
    default: return 'text-[#e4c388]';
  }
};

