import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuestNarrative = async (questTitle: string, characterName: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Narrate a short, gritty Wild West summary of ${characterName} completing the mission "${questTitle}". Use a dusty, frontier-focused tone with mention of revolvers, spurs, or the dry desert wind. Max 3 sentences.`,
      config: {
        temperature: 0.8,
      }
    });
    return response.text || "Mission complete. The frontier is one story richer.";
  } catch (error) {
    console.error("Narrative generation failed", error);
    return "The dust settled as another legend was written in the frontier.";
  }
};

export const generateDuelNarrative = async (player: string, opponent: string, result: 'Win' | 'Loss') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Describe a high-stakes quick-draw duel between ${player} and ${opponent} in a gritty Wild West style. ${player} ${result === 'Win' ? 'outdraws their opponent with cold precision' : 'is just a second too slow'}. Max 2 sentences.`,
    });
    return response.text || `A flash of steel! ${result === 'Win' ? player : opponent} stands victorious.`;
  } catch (error) {
    return `A flash of steel! ${result === 'Win' ? player : opponent} stands victorious.`;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Character, Item, Scene, Slot, Quest } from './types';
import { INITIAL_ITEMS, SHOP_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar, ItemTooltip } from './components/UI';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
import { Beer, ShieldCheck, Hammer, Sword, User, Package, Coins, Trophy, Zap } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  const [character, setCharacter] = useState<Character>({
    name: 'Silas "Old Dog" Vane',
    level: 1,
    exp: 0,
    gold: 500,
    baseStats: { aim: 15, reflexes: 12, grit: 10, charisma: 8, stamina: 12 },
    equipment: { Hat: null, Revolver: null, Rifle: null, Poncho: null, Boots: null, Badge: null, Belt: null },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [lastNarrative, setLastNarrative] = useState<string>('');
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);

  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    (Object.values(character.equipment) as (Item | null)[]).forEach(item => {
      if (item?.stats) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          if (typeof val === 'number') (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  useEffect(() => {
    if (!activeQuest) return;
    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.duration - Math.floor((Date.now() - prev.startTime) / 1000));
        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [activeQuest]);

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    const story = await generateQuestNarrative(quest.title, character.name);
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    setCharacter(prev => ({ ...prev, gold: prev.gold + quest.reward.gold, exp: prev.exp + quest.reward.exp, level: Math.floor((prev.exp + quest.reward.exp) / 1000) + 1 }));
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;
    const slot = item.slot;
    const currentEquipped = character.equipment[slot];
    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;
      return { ...prev, equipment: { ...prev.equipment, [slot]: item }, inventory: newInventory };
    });
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;
    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) return prev;
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;
      return { ...prev, equipment: { ...prev.equipment, [slot]: null }, inventory: newInventory };
    });
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) return;
    setActiveQuest({ quest, timeRemaining: quest.duration, startTime: Date.now() });
    setLastNarrative(`The trail ahead looks long. Riding out to ${quest.title}...`);
  };

  const runDuel = async () => {
    const win = totalStats.aim + totalStats.reflexes > 35;
    setIsLoadingNarrative(true);
    const story = await generateDuelNarrative(character.name, "Blackjack Bart", win ? 'Win' : 'Loss');
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    if (win) setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#250f0b]">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-[#250f0b] border-r border-[#663219] flex flex-col p-6 z-10 shadow-2xl">
        <div className="mb-10 text-center">
          <h1 className="western-font text-4xl text-[#cb9651] tracking-tighter uppercase leading-none">
            DUST<br/><span className="text-[#e4c388]">&</span><br/>GLORY
          </h1>
          <div className="text-[10px] typewriter-font uppercase tracking-widest text-[#a06335] mt-2">Dodge City Gazette</div>
        </div>

        <div className="space-y-2">
          {[
            { id: 'Character', icon: User, label: 'Ledger' },
            { id: 'Saloon', icon: Beer, label: 'Saloon' },
            { id: 'Sheriff', icon: ShieldCheck, label: 'Sheriff' },
            { id: 'Gunsmith', icon: Hammer, label: 'Smithy' },
            { id: 'HighNoon', icon: Sword, label: 'High Noon' }
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentScene(item.id as Scene)}
              className={`w-full flex items-center space-x-3 p-3 western-font text-xl transition-all border-l-4 ${
                currentScene === item.id 
                ? 'bg-[#663219]/40 text-[#cb9651] border-[#cb9651]' 
                : 'text-[#a06335] border-transparent hover:text-[#cb9651] hover:bg-[#663219]/20'
              }`}
            >
              <item.icon size={18} />
              <span>{item.label}</span>
            </button>
          ))}
        </div>

        <div className="mt-auto pt-8 border-t border-[#663219]">
          <div className="flex justify-between items-center mb-4 text-[#cb9651]">
            <div className="flex items-center space-x-2">
              <Coins size={16} />
              <span className="typewriter-font font-bold">{character.gold}</span>
            </div>
            <div className="flex items-center space-x-2">
              <Trophy size={16} />
              <span className="typewriter-font font-bold">LV.{character.level}</span>
            </div>
          </div>
          <StatsBar label="EXP" value={character.exp % 1000} max={1000} color="from-[#663219] to-[#cb9651]" />
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-10">

        {/* Narrative Box */}
        {(lastNarrative || isLoadingNarrative) && (
          <div className="mb-8 animate-in slide-in-from-top-4 duration-500 max-w-4xl mx-auto">
            <div className="parchment-panel p-6 border-2 border-[#a06335]/50 relative">
               <div className="absolute top-0 right-0 p-2 opacity-10">
                  <Zap size={40} />
               </div>
               <h3 className="western-font text-xl text-[#663219] mb-2 uppercase border-b border-[#663219]/20">Recent Telegram</h3>
               <p className="typewriter-font text-[#250f0b] leading-relaxed italic">
                 {isLoadingNarrative ? "Deciphering telegraph codes..." : `"${lastNarrative}"`}
               </p>
               {activeQuest && (
                <div className="mt-4">
                  <div className="flex justify-between text-[10px] typewriter-font text-[#663219] mb-1 font-bold">
                    <span>ON THE TRAIL: {activeQuest.quest.title}</span>
                    <span>{activeQuest.timeRemaining}S UNTIL SUNSET</span>
                  </div>
                  <div className="h-2 bg-[#663219]/20 border border-[#663219]/30 p-[1px]">
                    <div 
                      className="h-full bg-[#663219] transition-all" 
                      style={{ width: `${(activeQuest.timeRemaining / activeQuest.quest.duration) * 100}%` }}
                    ></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        <div className="max-w-6xl mx-auto">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {/* Paper Doll */}
              <div className="flex flex-col">
