                    <div className="col-start-1 row-start-2"><EquipSlot slot="Revolver" item={character.equipment.Revolver} onUnequip={() => handleUnequip('Revolver')} /></div>
                    <div className="col-start-2 row-start-2"><EquipSlot slot="Poncho" item={character.equipment.Poncho} onUnequip={() => handleUnequip('Poncho')} /></div>
                    <div className="col-start-3 row-start-2"><EquipSlot slot="Rifle" item={character.equipment.Rifle} onUnequip={() => handleUnequip('Rifle')} /></div>
                    <div className="col-start-2 row-start-3"><EquipSlot slot="Badge" item={character.equipment.Badge} onUnequip={() => handleUnequip('Badge')} /></div>
                    <div className="col-start-1 row-start-5"><EquipSlot slot="Belt" item={character.equipment.Belt} onUnequip={() => handleUnequip('Belt')} /></div>
                    <div className="col-start-3 row-start-5"><EquipSlot slot="Boots" item={character.equipment.Boots} onUnequip={() => handleUnequip('Boots')} /></div>
