                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8">
                    <StatsBar label="Aim" value={totalStats.aim} max={150} tooltip="Accuracy with firearms. Essential for outdrawing opponents and hitting long-range targets." />
                    <StatsBar label="Reflexes" value={totalStats.reflexes} max={150} tooltip="The speed of your trigger finger. Higher reflexes let you strike first in any encounter." />
                    <StatsBar label="Grit" value={totalStats.grit} max={150} tooltip="Hard-earned resilience. Reduces the impact of bad luck and physical trauma on the trail." />
                    <StatsBar label="Charisma" value={totalStats.charisma} max={150} tooltip="The gift of gab. Used for bluffing, bargaining, and convincing quest-givers to pay more." />
