              </div>

              {/* Inventory */}
              <div className="flex flex-col">
                 <h2 className="western-font text-4xl mb-6 text-[#cb9651] uppercase">Saddlebags</h2>
                 <BorderedCard className="flex-1" title="POSSESSIONS">
                    <div className="grid grid-cols-4 sm:grid-cols-5 gap-2">
                      {character.inventory.map((item, idx) => (
                        <InventorySlot 
                          key={idx} 
                          item={item} 
                          isSelected={selectedInventoryIdx === idx} 
                          onClick={() => item && setSelectedInventoryIdx(selectedInventoryIdx === idx ? null : idx)} 
                        />
                      ))}
