                  </BorderedCard>
                  <div className="space-y-6">
                    <div className="aspect-video wood-panel overflow-hidden relative">
                       <img src="https://images.unsplash.com/photo-1533158326339-7f3cf2404354?auto=format&fit=crop&q=80&w=800" className="w-full h-full object-cover opacity-60 sepia" alt="Saloon" />
                       <div className="absolute inset-0 flex items-center justify-center">
                          <span className="western-font text-3xl text-white drop-shadow-lg">DODGE CITY</span>
