                    <BorderedCard title="RUMORS">
                       <p className="typewriter-font text-xs text-[#e4c388]/70 italic leading-relaxed">"They say the Rattlesnake Gang is hidin' out in the canyons. Watch your back if you're headin' north."</p>
                    </BorderedCard>
                  </div>
               </div>
            </div>
          )}

          {currentScene === 'HighNoon' && (
            <div className="flex flex-col items-center justify-center min-h-[500px] border-8 border-[#663219] bg-[#250f0b]/60 relative overflow-hidden">
               <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/black-paper.png')] opacity-20"></div>
               <h2 className="western-font text-8xl text-[#cb9651] mb-2 drop-shadow-2xl">DRAW!</h2>
