               <div className="flex flex-col md:flex-row items-center space-y-10 md:space-y-0 md:space-x-32 relative z-10">
                  <div className="flex flex-col items-center">
                     <div className="w-40 h-40 rounded-full border-4 border-[#cb9651] overflow-hidden bg-slate-900 sepia">
                        <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=hero" alt="Hero" />
                     </div>
                     <span className="western-font text-2xl mt-4 text-[#cb9651] uppercase">{character.name}</span>
                  </div>
                  <div className="western-font text-6xl text-white/5 absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none">VS</div>
                  <div className="flex flex-col items-center">
                     <div className="w-40 h-40 rounded-full border-4 border-red-900 overflow-hidden bg-black contrast-125 sepia">
                        <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=blackjack" alt="Boss" />
                     </div>
                     <span className="western-font text-2xl mt-4 text-red-700 uppercase">Blackjack Bart</span>
                  </div>
               </div>

               <WesternButton 
                 variant="primary" 
                 className="mt-16 text-3xl px-16 py-6"
                 onClick={runDuel}
                 disabled={isLoadingNarrative}
               >
                 {isLoadingNarrative ? "COCKIN' HAMMER..." : "DRAW STEEL"}
               </WesternButton>
            </div>
          )}

          {(currentScene === 'Sheriff' || currentScene === 'Gunsmith') && (
            <div className="flex flex-col items-center justify-center h-64 text-center">
              <h2 className="western-font text-5xl text-[#cb9651] mb-4 uppercase">{currentScene}</h2>
              <div className="parchment-panel p-6 max-w-md">
                <p className="typewriter-font text-sm leading-relaxed">"The {currentScene.toLowerCase()} is out chasin' bounties right now. The office is closed until further notice."</p>
              </div>
              <WesternButton variant="secondary" className="mt-8" onClick={() => setCurrentScene('Character')}>Back to Camp</WesternButton>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const EquipSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  const content = (
    <div 
      className={`w-full h-full border-2 flex flex-col items-center justify-center relative transition-all cursor-default ${
        item ? 'bg-[#663219]/60 border-[#cb9651]' : 'bg-[#250f0b]/80 border-[#663219]/40 opacity-40'
      }`}
    >
      {!item && <span className="text-[8px] uppercase font-black text-[#e4c388] typewriter-font">{slot}</span>}
      {item && (
        <>
          <span className="text-[7px] leading-tight text-white font-bold typewriter-font uppercase p-1 text-center line-clamp-2">{item.name}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onUnequip(); }}
            className="absolute -top-1.5 -right-1.5 bg-red-900 text-white w-4 h-4 rounded-full text-[8px] flex items-center justify-center border border-white/20 hover:bg-red-700"
          >
            ×
          </button>
        </>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

const InventorySlot: React.FC<{ item: Item | null, isSelected: boolean, onClick: () => void }> = ({ item, isSelected, onClick }) => {
  const content = (
    <div 
      onClick={onClick}
      className={`aspect-square border-2 relative cursor-pointer flex flex-col items-center justify-center transition-all ${
        isSelected 
        ? 'border-[#cb9651] bg-[#663219]/60 shadow-lg scale-105 z-10' 
        : 'border-[#663219] bg-[#250f0b]/80 hover:border-[#cb9651]/50'
      }`}
    >
      {item ? (
        <>
          <span className="text-[7px] typewriter-font font-bold mt-1 uppercase opacity-40">{item.slot}</span>
          <div className="p-1 text-center">
            <span className="text-[8px] leading-tight text-[#e4c388] typewriter-font uppercase font-bold">{item.name}</span>
          </div>
        </>
      ) : (
        <div className="opacity-10"><Package size={16} /></div>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

export default App;

import React from 'react';
