interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'accent';
}

export const WesternButton: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', ...props }) => {
  const base = "px-8 py-2 uppercase font-bold action-button pixel-font text-lg tracking-widest border-2 ";
  const variants = {
    primary: "bg-[#cb9651] text-[#250f0b] border-[#e4c388] hover:bg-[#e4c388]",
    secondary: "bg-[#663219] text-[#e4c388] border-[#a06335] hover:bg-[#a06335]",
    accent: "bg-[#250f0b] text-[#cb9651] border-[#663219] hover:bg-[#663219]"
  };

  return (
    <button className={`${base} ${variants[variant]} ${className}`} {...props}>
      <span className="flex items-center justify-center gap-2">
        {children}
        <ChevronRight size={18} />
      </span>
    </button>
  );
};

