import React, { useState, useEffect, useMemo } from 'react';
import { Character, Item, Scene, Slot, Quest } from './types';
import { INITIAL_ITEMS, SHOP_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar, ItemTooltip } from './components/UI';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
import { Beer, ShieldCheck, Hammer, Sword, User, Package, Coins, Trophy, Zap, Map } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  const [character, setCharacter] = useState<Character>({
    name: 'Red "Ghost" Miller',
    level: 1,
    exp: 0,
    gold: 500,
    baseStats: { aim: 15, reflexes: 12, grit: 10, charisma: 8, stamina: 12 },
    equipment: { Hat: null, Revolver: null, Rifle: null, Poncho: null, Boots: null, Badge: null, Belt: null },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [lastNarrative, setLastNarrative] = useState<string>('');
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);

  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    (Object.values(character.equipment) as (Item | null)[]).forEach(item => {
      if (item?.stats) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          if (typeof val === 'number') (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  useEffect(() => {
    if (!activeQuest) return;
    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.duration - Math.floor((Date.now() - prev.startTime) / 1000));
        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [activeQuest]);

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    const story = await generateQuestNarrative(quest.title, character.name);
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    setCharacter(prev => ({ ...prev, gold: prev.gold + quest.reward.gold, exp: prev.exp + quest.reward.exp, level: Math.floor((prev.exp + quest.reward.exp) / 1000) + 1 }));
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;
    const slot = item.slot;
    const currentEquipped = character.equipment[slot];
    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;
      return { ...prev, equipment: { ...prev.equipment, [slot]: item }, inventory: newInventory };
    });
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;
    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) return prev;
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;
      return { ...prev, equipment: { ...prev.equipment, [slot]: null }, inventory: newInventory };
    });
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) return;
    setActiveQuest({ quest, timeRemaining: quest.duration, startTime: Date.now() });
    setLastNarrative(`Saddling up for objective: ${quest.title}...`);
  };

  const runDuel = async () => {
    const win = totalStats.aim + totalStats.reflexes > 35;
    setIsLoadingNarrative(true);
    const story = await generateDuelNarrative(character.name, "Slick Pete", win ? 'Win' : 'Loss');
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    if (win) setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#250f0b]">
      {/* Sidebar Navigation - JRPG Menu Style */}
      <nav className="w-full md:w-64 bg-[#250f0b] border-r-8 border-[#663219] flex flex-col p-6 z-10 shadow-[8px_0px_20px_rgba(0,0,0,0.5)]">
        <div className="mb-12 text-center group">
          <div className="relative inline-block">
             <div className="absolute inset-0 bg-[#cb9651] rotate-2 -z-10 group-hover:rotate-6 transition-transform"></div>
             <h1 className="pixel-font text-4xl text-[#250f0b] bg-[#e4c388] px-4 py-2 border-4 border-[#663219] tracking-tighter leading-none shadow-[4px_4px_0px_#cb9651]">
              DUST<br/>GLORY
            </h1>
          </div>
          <div className="text-[9px] pixel-font text-[#cb9651] mt-4 tracking-widest animate-pulse">FRONT-LINE_READY</div>
        </div>

        <div className="space-y-4">
          {[
            { id: 'Character', icon: User, label: 'HERO' },
            { id: 'Saloon', icon: Beer, label: 'HUB' },
            { id: 'Sheriff', icon: ShieldCheck, label: 'BOUNTY' },
            { id: 'Gunsmith', icon: Hammer, label: 'FORGE' },
            { id: 'HighNoon', icon: Sword, label: 'ARENA' }
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentScene(item.id as Scene)}
              className={`w-full flex items-center justify-between p-3 pixel-font text-xl transition-all clip-path-polygon(0 0, 100% 0, 90% 100%, 0 100%) ${
                currentScene === item.id 
                ? 'bg-[#cb9651] text-[#250f0b] translate-x-4 shadow-[-8px_0px_0px_#e4c388]' 
                : 'text-[#a06335] hover:text-[#e4c388] hover:bg-[#663219]/30'
              }`}
            >
              <span className="flex items-center gap-3">
                <item.icon size={18} />
                {item.label}
              </span>
              {currentScene === item.id && <ChevronRight size={16} />}
            </button>
          ))}
        </div>

        <div className="mt-auto pt-8 border-t-4 border-[#663219]">
          <div className="flex justify-between items-center mb-4 text-[#e4c388]">
            <div className="flex flex-col items-center">
              <span className="text-[10px] pixel-font text-[#cb9651]">GOLD</span>
              <div className="flex items-center space-x-1">
                <Coins size={14} className="text-[#cb9651]" />
                <span className="typewriter-font font-bold">{character.gold}</span>
              </div>
            </div>
            <div className="flex flex-col items-center">
              <span className="text-[10px] pixel-font text-[#cb9651]">RANK</span>
              <div className="flex items-center space-x-1">
                <Trophy size={14} className="text-[#cb9651]" />
                <span className="typewriter-font font-bold">{character.level}</span>
              </div>
            </div>
          </div>
          <StatsBar label="XP_LOAD" value={character.exp % 1000} max={1000} color="from-[#cb9651] to-[#e4c388]" />
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">

