          )}

          {currentScene === 'HighNoon' && (
            <div className="flex flex-col items-center justify-center min-h-[600px] border-[16px] border-[#663219] bg-[#250f0b] relative overflow-hidden shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
               <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20"></div>

               <div className="relative z-10 text-center mb-16">
                  <h2 className="pixel-font text-9xl text-[#cb9651] animate-bounce drop-shadow-[10px_10px_0px_#250f0b]">DRAW!</h2>
                  <div className="h-1 w-64 bg-[#cb9651] mx-auto mt-2 animate-pulse"></div>
                  <p className="pixel-font text-xl text-[#e4c388] mt-4 tracking-[0.8em] opacity-80">HIGH_NOON_OVERRIDE</p>
               </div>

               <div className="flex flex-col md:flex-row items-center space-y-16 md:space-y-0 md:space-x-40 relative z-10">
                  <div className="flex flex-col items-center">
                     <div className="w-48 h-48 border-8 border-[#cb9651] bg-[#250f0b] p-4 shadow-[12px_12px_0px_#663219]">
                        <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=hero" alt="Hero" className="w-full h-full object-contain brightness-90 contrast-110" />
                     </div>
                     <span className="pixel-font text-3xl mt-6 text-[#cb9651] tracking-tighter">{character.name}</span>
                     <div className="mt-2 text-[10px] pixel-font text-[#e4c388]">SYNC_RATE: {totalStats.aim + totalStats.reflexes}%</div>
                  </div>

                  <div className="pixel-font text-[120px] text-[#cb9651]/5 absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none select-none">BATTLE</div>

                  <div className="flex flex-col items-center">
                     <div className="w-48 h-48 border-8 border-red-700 bg-[#250f0b] p-4 shadow-[12px_12px_0px_#250f0b]">
                        <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=slick" alt="Boss" className="w-full h-full object-contain grayscale brightness-50 contrast-150" />
                     </div>
                     <span className="pixel-font text-3xl mt-6 text-red-700 tracking-tighter">SLICK_PETE_v2</span>
                     <div className="mt-2 text-[10px] pixel-font text-red-700">SYNC_RATE: 45%</div>
                  </div>
               </div>

               <WesternButton 
                 variant="primary" 
                 className="mt-24 text-5xl px-24 py-10 shadow-[8px_8px_0px_#250f0b]"
                 onClick={runDuel}
                 disabled={isLoadingNarrative}
               >
                 {isLoadingNarrative ? "LOADING_STEEL..." : "INITIALIZE_DRAW"}
               </WesternButton>
            </div>
          )}

          {(currentScene === 'Sheriff' || currentScene === 'Gunsmith') && (
            <div className="flex flex-col items-center justify-center h-96 text-center">
              <h2 className="pixel-font text-7xl text-[#cb9651] mb-6 italic">{currentScene}_MODULE</h2>
              <div className="bg-[#e4c388] p-8 max-w-lg border-b-8 border-r-8 border-[#cb9651] text-[#250f0b]">
                <p className="pixel-font text-xl leading-relaxed mb-4">"TERMINAL_LOCKED"</p>
                <p className="typewriter-font text-sm leading-relaxed italic">"THE {currentScene.toUpperCase()} IS CURRENTLY ON AN OFF-GRID MISSION. SYSTEM UPDATE PENDING NEXT SOLAR CYCLE."</p>
              </div>
              <WesternButton variant="accent" className="mt-12" onClick={() => setCurrentScene('Character')}>BACK_TO_BASE</WesternButton>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const EquipSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  const content = (
    <div 
      className={`w-full h-full border-4 flex flex-col items-center justify-center relative transition-all cursor-default shadow-[4px_4px_0px_#250f0b] ${
        item ? 'bg-[#663219] border-[#cb9651]' : 'bg-[#250f0b] border-[#663219] opacity-40'
      }`}
    >
      {!item && <span className="text-[7px] pixel-font font-black text-[#e4c388] text-center p-1 leading-none">{slot}</span>}
      {item && (
        <>
          <span className="text-[7px] leading-none text-white font-bold pixel-font uppercase p-1 text-center line-clamp-3">{item.name}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onUnequip(); }}
            className="absolute -top-3 -right-3 bg-red-700 text-white w-6 h-6 text-[12px] flex items-center justify-center border-2 border-white hover:bg-red-500 pixel-font font-bold"
          >
            X
          </button>
        </>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

const InventorySlot: React.FC<{ item: Item | null, isSelected: boolean, onClick: () => void }> = ({ item, isSelected, onClick }) => {
  const content = (
    <div 
      onClick={onClick}
      className={`aspect-square border-4 relative cursor-pointer flex flex-col items-center justify-center transition-all shadow-[4px_4px_0px_rgba(0,0,0,0.3)] ${
        isSelected 
        ? 'border-[#cb9651] bg-[#663219] scale-105 z-10 shadow-[6px_6px_0px_#250f0b]' 
        : 'border-[#663219] bg-[#250f0b] hover:border-[#a06335]'
      }`}
    >
      {item ? (
        <>
          <span className="text-[6px] pixel-font font-bold mt-1 uppercase opacity-40 text-[#cb9651]">{item.slot}</span>
          <div className="p-1 text-center">
            <span className="text-[8px] leading-none text-[#e4c388] pixel-font uppercase font-bold">{item.name}</span>
          </div>
        </>
      ) : (
        <div className="opacity-10"><Package size={20} className="text-[#cb9651]" /></div>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Character, Item, Scene, Slot, Quest } from './types';
import { INITIAL_ITEMS, SHOP_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar, ItemTooltip } from './components/UI';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
// Added ChevronRight to the imports from lucide-react
import { Beer, ShieldCheck, Hammer, Sword, User, Package, Coins, Trophy, Zap, Map, ChevronRight } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  const [character, setCharacter] = useState<Character>({
    name: 'Red "Ghost" Miller',
    level: 1,
    exp: 0,
    gold: 500,
    baseStats: { aim: 15, reflexes: 12, grit: 10, charisma: 8, stamina: 12 },
    equipment: { Hat: null, Revolver: null, Rifle: null, Poncho: null, Boots: null, Badge: null, Belt: null },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [lastNarrative, setLastNarrative] = useState<string>('');
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);

  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    (Object.values(character.equipment) as (Item | null)[]).forEach(item => {
      if (item?.stats) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          if (typeof val === 'number') (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  useEffect(() => {
    if (!activeQuest) return;
    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.duration - Math.floor((Date.now() - prev.startTime) / 1000));
        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [activeQuest]);

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    const story = await generateQuestNarrative(quest.title, character.name);
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    setCharacter(prev => ({ ...prev, gold: prev.gold + quest.reward.gold, exp: prev.exp + quest.reward.exp, level: Math.floor((prev.exp + quest.reward.exp) / 1000) + 1 }));
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;
    const slot = item.slot;
    const currentEquipped = character.equipment[slot];
    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;
      return { ...prev, equipment: { ...prev.equipment, [slot]: item }, inventory: newInventory };
    });
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;
    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) return prev;
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;
      return { ...prev, equipment: { ...prev.equipment, [slot]: null }, inventory: newInventory };
    });
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) return;
    setActiveQuest({ quest, timeRemaining: quest.duration, startTime: Date.now() });
    setLastNarrative(`Saddling up for objective: ${quest.title}...`);
  };

  const runDuel = async () => {
    const win = totalStats.aim + totalStats.reflexes > 35;
    setIsLoadingNarrative(true);
    const story = await generateDuelNarrative(character.name, "Slick Pete", win ? 'Win' : 'Loss');
    setLastNarrative(story);
    setIsLoadingNarrative(false);
    if (win) setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#250f0b]">
      {/* Sidebar Navigation - JRPG Menu Style */}
      <nav className="w-full md:w-64 bg-[#250f0b] border-r-8 border-[#663219] flex flex-col p-6 z-10 shadow-[8px_0px_20px_rgba(0,0,0,0.5)]">
        <div className="mb-12 text-center group">
          <div className="relative inline-block">
             <div className="absolute inset-0 bg-[#cb9651] rotate-2 -z-10 group-hover:rotate-6 transition-transform"></div>
             <h1 className="pixel-font text-4xl text-[#250f0b] bg-[#e4c388] px-4 py-2 border-4 border-[#663219] tracking-tighter leading-none shadow-[4px_4px_0px_#cb9651]">
              DUST<br/>GLORY
            </h1>
          </div>
          <div className="text-[9px] pixel-font text-[#cb9651] mt-4 tracking-widest animate-pulse">FRONT-LINE_READY</div>
        </div>

        <div className="space-y-4">
          {[
            { id: 'Character', icon: User, label: 'HERO' },
            { id: 'Saloon', icon: Beer, label: 'HUB' },
            { id: 'Sheriff', icon: ShieldCheck, label: 'BOUNTY' },
            { id: 'Gunsmith', icon: Hammer, label: 'FORGE' },
            { id: 'HighNoon', icon: Sword, label: 'ARENA' }
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentScene(item.id as Scene)}
              className={`w-full flex items-center justify-between p-3 pixel-font text-xl transition-all clip-path-polygon(0 0, 100% 0, 90% 100%, 0 100%) ${
                currentScene === item.id 
                ? 'bg-[#cb9651] text-[#250f0b] translate-x-4 shadow-[-8px_0px_0px_#e4c388]' 
                : 'text-[#a06335] hover:text-[#e4c388] hover:bg-[#663219]/30'
              }`}
            >
              <span className="flex items-center gap-3">
                <item.icon size={18} />
                {item.label}
              </span>
              {currentScene === item.id && <ChevronRight size={16} />}
            </button>
          ))}
        </div>

        <div className="mt-auto pt-8 border-t-4 border-[#663219]">
          <div className="flex justify-between items-center mb-4 text-[#e4c388]">
            <div className="flex flex-col items-center">
              <span className="text-[10px] pixel-font text-[#cb9651]">GOLD</span>
              <div className="flex items-center space-x-1">
                <Coins size={14} className="text-[#cb9651]" />
                <span className="typewriter-font font-bold">{character.gold}</span>
              </div>
            </div>
            <div className="flex flex-col items-center">
              <span className="text-[10px] pixel-font text-[#cb9651]">RANK</span>
              <div className="flex items-center space-x-1">
                <Trophy size={14} className="text-[#cb9651]" />
                <span className="typewriter-font font-bold">{character.level}</span>
              </div>
            </div>
          </div>
          <StatsBar label="XP_LOAD" value={character.exp % 1000} max={1000} color="from-[#cb9651] to-[#e4c388]" />
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">

        {/* Narrative / Battle Log */}
        {(lastNarrative || isLoadingNarrative) && (
          <div className="mb-8 animate-in slide-in-from-top-4 duration-300 max-w-4xl mx-auto">
            <div className="bg-[#e4c388] border-b-8 border-r-8 border-[#cb9651] p-6 relative">
               <div className="absolute top-0 right-0 p-2 opacity-20 text-[#250f0b]">
                  <Map size={48} />
               </div>
               <h3 className="pixel-font text-2xl text-[#250f0b] mb-3 flex items-center gap-2">
                 <Zap className="fill-[#250f0b]" size={20} />
                 FRONT_UPDATE
               </h3>
               <div className="bg-[#250f0b] p-4 border-2 border-[#663219]">
                 <p className="typewriter-font text-[#e4c388] leading-relaxed italic">
                   {isLoadingNarrative ? "> UPDATING FRONTIER DATA..." : `"${lastNarrative}"`}
                 </p>
               </div>
               {activeQuest && (
                <div className="mt-4">
                  <div className="flex justify-between text-[10px] pixel-font text-[#663219] mb-1 font-bold">
                    <span>DEPLOYED: {activeQuest.quest.title}</span>
                    <span className="animate-pulse">{activeQuest.timeRemaining}S_LEFT</span>
                  </div>
                  <div className="h-3 bg-[#250f0b] border-2 border-[#663219] p-[2px]">
                    <div 
                      className="h-full bg-[#cb9651] transition-all duration-1000" 
                      style={{ width: `${(activeQuest.timeRemaining / activeQuest.quest.duration) * 100}%` }}
                    ></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        <div className="max-w-6xl mx-auto">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              {/* Profile / Armor Sync */}
              <div className="flex flex-col">
                <div className="flex items-center gap-4 mb-8">
                   <div className="bg-[#cb9651] p-2 rotate-45 border-4 border-[#250f0b] shadow-[4px_4px_0px_#a06335]">
                      <User size={32} className="text-[#250f0b] -rotate-45" />
                   </div>
                   <h2 className="pixel-font text-5xl text-[#e4c388] italic drop-shadow-[4px_4px_0px_#250f0b]">UNIT_PROFILE</h2>
                </div>

                <div className="aspect-[3/4] max-w-sm mx-auto w-full bg-[#250f0b] border-8 border-[#663219] p-8 relative flex flex-col items-center shadow-[12px_12px_0px_#a06335]">
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>

                  {/* Equipment Grid */}
                  <div className="relative z-10 w-full h-full grid grid-cols-3 grid-rows-5 gap-4">
                    <div className="col-start-2 row-start-1"><EquipSlot slot="Hat" item={character.equipment.Hat} onUnequip={() => handleUnequip('Hat')} /></div>
                    <div className="col-start-1 row-start-2"><EquipSlot slot="Revolver" item={character.equipment.Revolver} onUnequip={() => handleUnequip('Revolver')} /></div>
                    <div className="col-start-2 row-start-2"><EquipSlot slot="Poncho" item={character.equipment.Poncho} onUnequip={() => handleUnequip('Poncho')} /></div>
                    <div className="col-start-3 row-start-2"><EquipSlot slot="Rifle" item={character.equipment.Rifle} onUnequip={() => handleUnequip('Rifle')} /></div>
                    <div className="col-start-2 row-start-3"><EquipSlot slot="Badge" item={character.equipment.Badge} onUnequip={() => handleUnequip('Badge')} /></div>
                    <div className="col-start-1 row-start-5"><EquipSlot slot="Belt" item={character.equipment.Belt} onUnequip={() => handleUnequip('Belt')} /></div>
                    <div className="col-start-3 row-start-5"><EquipSlot slot="Boots" item={character.equipment.Boots} onUnequip={() => handleUnequip('Boots')} /></div>
                  </div>
                </div>

                <BorderedCard className="mt-10" title="VITAL_SYSTEMS">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8">
                    <StatsBar 
                      label="AIM" 
                      value={totalStats.aim} 
                      max={150} 
                      tooltip="Ballistic accuracy. Essential for outdrawing outlaws and hitting targets at high noon." 
                    />
                    <StatsBar 
                      label="REFLEX" 
                      value={totalStats.reflexes} 
                      max={150} 
                      tooltip="Neural response time. Determines if you draw first in a quick-draw duel." 
                    />
                    <StatsBar 
                      label="GRIT" 
                      value={totalStats.grit} 
                      max={150} 
                      tooltip="Combat resilience. Reduces the impact of injuries and survival hazards on the trail." 
                    />
                    <StatsBar 
                      label="CHARIS" 
                      value={totalStats.charisma} 
                      max={150} 
                      tooltip="Interpersonal link. Used for bluffing, bartering, and securing high-value bounty contracts." 
                    />
                    <StatsBar 
                      label="STAM" 
                      value={totalStats.stamina} 
                      max={150} 
                      tooltip="Energy endurance. Required for sustained expeditions across the wasteland plains." 
                    />
                  </div>
                </BorderedCard>
              </div>

              {/* Cargo / Inventory */}
              <div className="flex flex-col">
                 <div className="flex items-center gap-4 mb-8">
                   <div className="bg-[#a06335] p-2 border-4 border-[#250f0b] shadow-[4px_4px_0px_#663219]">
                      <Package size={32} className="text-[#e4c388]" />
                   </div>
                   <h2 className="pixel-font text-5xl text-[#e4c388] italic drop-shadow-[4px_4px_0px_#250f0b]">CARGO_BAY</h2>
                </div>

                 <BorderedCard className="flex-1" title="STORED_ASSETS">
                    <div className="grid grid-cols-4 sm:grid-cols-5 gap-3">
                      {character.inventory.map((item, idx) => (
                        <InventorySlot 
                          key={idx} 
                          item={item} 
                          isSelected={selectedInventoryIdx === idx} 
                          onClick={() => item && setSelectedInventoryIdx(selectedInventoryIdx === idx ? null : idx)} 
                        />
                      ))}
                    </div>

                    {selectedInventoryIdx !== null && character.inventory[selectedInventoryIdx] && (
                      <div className="mt-8 p-6 bg-[#250f0b] border-4 border-[#cb9651] animate-in zoom-in-95 duration-200">
                        <div className="flex justify-between items-start mb-4">
                          <h4 className="pixel-font text-3xl text-[#cb9651]">{character.inventory[selectedInventoryIdx]!.name}</h4>
                          <span className="bg-[#663219] px-3 py-1 text-[10px] pixel-font text-[#e4c388]">SYNC_LVL: 01</span>
                        </div>
                        <p className="typewriter-font text-sm text-[#e4c388]/70 mb-6 italic leading-relaxed">
                          "{character.inventory[selectedInventoryIdx]!.description}"
                        </p>
                        <WesternButton 
                          onClick={() => handleEquip(selectedInventoryIdx!)} 
                          className="w-full text-xl py-4"
                          variant="primary"
                        >
                          SYNC_UNIT
                        </WesternButton>
                      </div>
                    )}
                 </BorderedCard>
              </div>
            </div>
          )}

          {currentScene === 'Saloon' && (
            <div className="max-w-4xl mx-auto">
               <h2 className="pixel-font text-6xl mb-12 text-[#cb9651] text-center border-b-8 border-[#663219] pb-6 italic">THE_HUB_TERMINAL</h2>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <BorderedCard title="CONTRACT_BOARD">
                    <div className="space-y-4">
                      {QUESTS.map(q => (
                        <div key={q.id} className="p-4 bg-[#250f0b] border-2 border-[#a06335] flex justify-between items-center group hover:bg-[#663219]/20 transition-all cursor-pointer">
                          <div>
                            <h4 className="pixel-font text-xl text-[#e4c388] group-hover:text-[#cb9651]">{q.title}</h4>
                            <div className="text-[10px] pixel-font text-[#cb9651] mt-2 flex items-center gap-2">
                              <span className="bg-[#250f0b] px-2 border border-[#663219]">{q.difficulty}</span>
                              <span className="text-[#a06335]">LOADOUT: {q.reward.gold}C | {q.reward.exp}XP</span>
                            </div>
                          </div>
                          <WesternButton 
                            variant="secondary" 
                            disabled={!!activeQuest}
                            onClick={() => startQuest(q)}
                            className="py-1 px-4 text-xs"
                          >
                            RUN
                          </WesternButton>
                        </div>
                      ))}
                    </div>
                  </BorderedCard>
                  <div className="space-y-8">
                    <div className="aspect-video bg-[#250f0b] border-8 border-[#663219] relative overflow-hidden group">
                       <img src="https://images.unsplash.com/photo-1533158326339-7f3cf2404354?auto=format&fit=crop&q=80&w=800" className="w-full h-full object-cover opacity-40 sepia hover:sepia-0 transition-all duration-500" alt="Saloon" />
                       <div className="absolute inset-0 bg-gradient-to-t from-[#250f0b] to-transparent"></div>
                       <div className="absolute bottom-4 left-4 flex items-center gap-3">
                          <div className="w-8 h-8 bg-[#cb9651] animate-spin"></div>
                          <span className="pixel-font text-2xl text-[#e4c388] drop-shadow-[2px_2px_0px_#250f0b]">DODGE_SECTOR_7</span>
                       </div>
                    </div>
                    <BorderedCard title="ENCRYPTED_INTEL">
                       <p className="typewriter-font text-xs text-[#e4c388]/60 italic leading-relaxed border-l-4 border-[#cb9651] pl-3 py-1">
                         "REPORTS INDICATE THE COYOTE SYNDICATE IS GATHERING NEAR THE OIL FIELDS. CAUTION ADVISED."
                       </p>
                    </BorderedCard>
                  </div>
               </div>
            </div>
          )}

          {currentScene === 'HighNoon' && (
            <div className="flex flex-col items-center justify-center min-h-[600px] border-[16px] border-[#663219] bg-[#250f0b] relative overflow-hidden shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
               <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20"></div>

               <div className="relative z-10 text-center mb-16">
                  <h2 className="pixel-font text-9xl text-[#cb9651] animate-bounce drop-shadow-[10px_10px_0px_#250f0b]">DRAW!</h2>
                  <div className="h-1 w-64 bg-[#cb9651] mx-auto mt-2 animate-pulse"></div>
                  <p className="pixel-font text-xl text-[#e4c388] mt-4 tracking-[0.8em] opacity-80">HIGH_NOON_OVERRIDE</p>
               </div>

               <div className="flex flex-col md:flex-row items-center space-y-16 md:space-y-0 md:space-x-40 relative z-10">
                  <div className="flex flex-col items-center">
                     <div className="w-48 h-48 border-8 border-[#cb9651] bg-[#250f0b] p-4 shadow-[12px_12px_0px_#663219]">
                        <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=hero" alt="Hero" className="w-full h-full object-contain brightness-90 contrast-110" />
                     </div>
                     <span className="pixel-font text-3xl mt-6 text-[#cb9651] tracking-tighter">{character.name}</span>
                     <div className="mt-2 text-[10px] pixel-font text-[#e4c388]">SYNC_RATE: {totalStats.aim + totalStats.reflexes}%</div>
                  </div>

                  <div className="pixel-font text-[120px] text-[#cb9651]/5 absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none select-none">BATTLE</div>

                  <div className="flex flex-col items-center">
                     <div className="w-48 h-48 border-8 border-red-700 bg-[#250f0b] p-4 shadow-[12px_12px_0px_#250f0b]">
                        <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=slick" alt="Boss" className="w-full h-full object-contain grayscale brightness-50 contrast-150" />
                     </div>
                     <span className="pixel-font text-3xl mt-6 text-red-700 tracking-tighter">SLICK_PETE_v2</span>
                     <div className="mt-2 text-[10px] pixel-font text-red-700">SYNC_RATE: 45%</div>
                  </div>
               </div>

               <WesternButton 
                 variant="primary" 
                 className="mt-24 text-5xl px-24 py-10 shadow-[8px_8px_0px_#250f0b]"
                 onClick={runDuel}
                 disabled={isLoadingNarrative}
               >
                 {isLoadingNarrative ? "LOADING_STEEL..." : "INITIALIZE_DRAW"}
               </WesternButton>
            </div>
          )}

          {(currentScene === 'Sheriff' || currentScene === 'Gunsmith') && (
            <div className="flex flex-col items-center justify-center h-96 text-center">
              <h2 className="pixel-font text-7xl text-[#cb9651] mb-6 italic">{currentScene}_MODULE</h2>
              <div className="bg-[#e4c388] p-8 max-w-lg border-b-8 border-r-8 border-[#cb9651] text-[#250f0b]">
                <p className="pixel-font text-xl leading-relaxed mb-4">"TERMINAL_LOCKED"</p>
                <p className="typewriter-font text-sm leading-relaxed italic">"THE {currentScene.toUpperCase()} IS CURRENTLY ON AN OFF-GRID MISSION. SYSTEM UPDATE PENDING NEXT SOLAR CYCLE."</p>
              </div>
              <WesternButton variant="accent" className="mt-12" onClick={() => setCurrentScene('Character')}>BACK_TO_BASE</WesternButton>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const EquipSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  const content = (
    <div 
      className={`w-full h-full border-4 flex flex-col items-center justify-center relative transition-all cursor-default shadow-[4px_4px_0px_#250f0b] ${
        item ? 'bg-[#663219] border-[#cb9651]' : 'bg-[#250f0b] border-[#663219] opacity-40'
      }`}
    >
      {!item && <span className="text-[7px] pixel-font font-black text-[#e4c388] text-center p-1 leading-none">{slot}</span>}
      {item && (
        <>
          <span className="text-[7px] leading-none text-white font-bold pixel-font uppercase p-1 text-center line-clamp-3">{item.name}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onUnequip(); }}
            className="absolute -top-3 -right-3 bg-red-700 text-white w-6 h-6 text-[12px] flex items-center justify-center border-2 border-white hover:bg-red-500 pixel-font font-bold"
          >
            X
          </button>
        </>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

const InventorySlot: React.FC<{ item: Item | null, isSelected: boolean, onClick: () => void }> = ({ item, isSelected, onClick }) => {
  const content = (
    <div 
      onClick={onClick}
      className={`aspect-square border-4 relative cursor-pointer flex flex-col items-center justify-center transition-all shadow-[4px_4px_0px_rgba(0,0,0,0.3)] ${
        isSelected 
        ? 'border-[#cb9651] bg-[#663219] scale-105 z-10 shadow-[6px_6px_0px_#250f0b]' 
        : 'border-[#663219] bg-[#250f0b] hover:border-[#a06335]'
      }`}
    >
      {item ? (
        <>
          <span className="text-[6px] pixel-font font-bold mt-1 uppercase opacity-40 text-[#cb9651]">{item.slot}</span>
          <div className="p-1 text-center">
            <span className="text-[8px] leading-none text-[#e4c388] pixel-font uppercase font-bold">{item.name}</span>
          </div>
        </>
      ) : (
        <div className="opacity-10"><Package size={20} className="text-[#cb9651]" /></div>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

export default App;
